#include <stdio.h>
#include <string.h>
#include <mqueue.h>
#include <fcntl.h>
#include <sys/stat.h>

int main(void) {
    struct mq_attr attr = { .mq_maxmsg = 10, .mq_msgsize = 128 };
    mqd_t mq = mq_open("/kf_mq_sendrecv", O_CREAT | O_RDWR, 0644, &attr);

    const char *msg = "Hello MQ";
    mq_send(mq, msg, strlen(msg), 0);

    char buf[128];
    unsigned int prio;
    ssize_t n = mq_receive(mq, buf, sizeof(buf), &prio);
    buf[n] = '\0';
    printf("Received: %s (prio=%u)\n", buf, prio);

    mq_close(mq);
    mq_unlink("/kf_mq_sendrecv");
    return 0;
}

